    "values": [
      "\\$\\d+(?:\\.\\d{2})?",
      "\\d+(?:\\.\\d{2})?\\s*(?:USD|EUR|GBP|CAD)"
    ]
  },
  {
    "attribute": "hasOrderNumber",
    "field": "body",
    "operation": "regexAny",
    "values": [
      "(?:Order|Invoice|Receipt)\\s*#?\\s*:?\\s*[A-Z0-9-]+",
      "#[A-Z]{2,}-\\d{4}-\\d+"
    ]
  }
]' config/email-categorizer-config.json > config/email-categorizer-config.tmp && mv config/email-categorizer-config.tmp config/email-categorizer-config.json

